// Load roster.yml. Extract client.discord_id, channel IDs.
const fs = require('fs');
const yaml = require('js-yaml');
const path = process.env.ROSTER_CONFIG_PATH || '/data/roster.yml';
let roster;
try {
  roster = yaml.load(fs.readFileSync(path, 'utf8'));
} catch (e) {
  throw new Error('Welcome Draft: cannot load roster.yml: ' + e.message);
}
return [{
  json: {
    client_discord_id: roster.client.discord_id,
    client_channel_id: roster.client_channel_id,
    team_lead_channel_id: roster.team_lead_channel_id,
    team_lead_discord_id: roster.team_lead.discord_id,
    roster_names: roster.team.map(m => m.name).concat([roster.team_lead.name]),
    manual: false
  }
}];

// Compare snapshots to find new members.
// If no known snapshot: save current as baseline and stop (first-run seed).
// Only proceed if client.discord_id is in new_members.
const currentMembersRaw = $node['Get Current Guild Members'].json;
const rosterData = $node['Load Roster'].json;
const snapshotRow = $input.first().json;

const currentMembers = Array.isArray(currentMembersRaw) ? currentMembersRaw.map(m => m.user && m.user.id).filter(Boolean) : [];
const clientDiscordId = rosterData.client_discord_id;

if (!snapshotRow || !snapshotRow.value_json) {
  // First run: seed with current members, no welcome triggered
  return [{ json: {
    seed_only: true,
    current_members: currentMembers,
    client_discord_id: clientDiscordId,
    client_channel_id: rosterData.client_channel_id,
    team_lead_channel_id: rosterData.team_lead_channel_id,
    team_lead_discord_id: rosterData.team_lead_discord_id,
    roster_names: rosterData.roster_names
  }}];
}

const knownMembers = typeof snapshotRow.value_json === 'string' ? JSON.parse(snapshotRow.value_json) : snapshotRow.value_json;
const knownSet = new Set(Array.isArray(knownMembers) ? knownMembers : []);
const newMembers = currentMembers.filter(id => !knownSet.has(id));
const clientIsNew = newMembers.includes(clientDiscordId);

return [{ json: {
  seed_only: false,
  client_is_new: clientIsNew,
  current_members: currentMembers,
  client_discord_id: clientDiscordId,
  client_channel_id: rosterData.client_channel_id,
  team_lead_channel_id: rosterData.team_lead_channel_id,
  team_lead_discord_id: rosterData.team_lead_discord_id,
  roster_names: rosterData.roster_names
}}];

// Build Ollama request for welcome message draft.
// System prompt is verbatim from the planner.
const data = $node['Save Updated Snapshot'].json;
const llmRequest = {
  model: 'llama3',
  messages: [
    {
      role: 'system',
      content: 'You are a project coordination assistant. Draft a brief, warm welcome message for the client who has just joined the project\'s Discord channel. The message should explain that they can ask questions about the project here and expect project-level updates. Keep it under 80 words. Friendly and professional tone. Do not reference any individual team members by name.'
    },
    {
      role: 'user',
      content: 'Draft a welcome message for our client who just joined the channel.'
    }
  ],
  temperature: 0.3,
  stream: false
};
return [{ json: {
  llm_request: llmRequest,
  client_channel_id: data.client_channel_id,
  team_lead_channel_id: data.team_lead_channel_id,
  team_lead_discord_id: data.team_lead_discord_id,
  roster_names: data.roster_names
}}];

// Extract welcome text from LLM response.
const result = $input.first().json;
const data = $node['Build Welcome Message Prompt'].json;

let welcomeText = 'Welcome! You can ask questions about the project here and we will provide project-level updates. Feel free to ask anything.';
if (!result.error && result.choices && result.choices[0]) {
  welcomeText = result.choices[0].message.content || welcomeText;
}

return [{ json: {
  welcome_text_raw: welcomeText,
  ...data
}}];

// Privacy Validation: scan welcome text for roster member names.
// Welcome messages should not name team members.
const data = $json;
const rosterNames = data.roster_names || [];
let text = data.welcome_text_raw || '';
const warnings = [];

for (const name of rosterNames) {
  if (!name) continue;
  const escapedName = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`\\b${escapedName}\\b`, 'gi');
  if (regex.test(text)) {
    text = text.replace(regex, '[REMOVED — individual attribution]');
    warnings.push(name);
  }
}

if (warnings.length > 0) {
  text += `\n\n[Warning: individual attribution removed: ${warnings.join(', ')}]`;
}

return [{ json: {
  welcome_text: text,
  client_channel_id: data.client_channel_id,
  team_lead_channel_id: data.team_lead_channel_id,
  team_lead_discord_id: data.team_lead_discord_id,
  privacy_warnings: warnings
}}];
